// ── Validate ─────────────────────────────────────────────
const body = $input.first().json.body || $input.first().json;

if (!body.title || body.title.trim().length === 0) {
  throw new Error('Validation failed: title is required');
}
if (!body.content || body.content.trim().length === 0) {
  throw new Error('Validation failed: content is required');
}
if (body.title.trim().length < 5) {
  throw new Error('Validation failed: title must be at least 5 characters');
}
if (body.content.trim().length < 50) {
  throw new Error('Validation failed: content must be at least 50 characters');
}

// ── Normalize ─────────────────────────────────────────────
const now = new Date().toISOString();
const rand = Math.random().toString(36).substring(2, 10);
const articleId = 'art_' + rand + '_' + Date.now().toString(36);

const normalized = {
  article_id:       articleId,
  created_at:       now,
  title:            body.title.trim(),
  content:          body.content.trim(),
  category:         (body.category  || '').trim(),
  author:           (body.author    || '').trim(),
  published_at:     (body.published_at || '').trim(),
  tags_csv:         (body.tags || '').split(',').map(t => t.trim()).filter(Boolean).join(', '),
  raw_payload:      JSON.stringify(body),
  seo_status:       'pending',
  seo_requested_at: now,
  seo_processed_at: '',
  seo_error:        ''
};

return [{ json: normalized }];
